import BaseController from "./BaseController";
import Input from "sap/m/Input";
import MessageBox from "sap/m/MessageBox";
import LaravelUi5 from "com/laravelui5/core/LaravelUi5";
import JSONModel from "sap/ui/model/json/JSONModel";
import {URLHelper} from "sap/m/library";

interface LoginResponse {
	message: string;
	redirect: string;
}

interface ActionError {
	cause: { message: string };
	statusText: string;
}

/**
 * @namespace io.pragmatiqu.auth.controller
 */
export default class Login extends BaseController {
	public onInit(): void {
		this.getView().addEventDelegate({
			onAfterShow: () => {
				setTimeout(() => (this.byId("emailInput") as Input).focus(), 0);
			}
		});
	}

	public async onLogin(): Promise<void> {
		const login = <JSONModel> this.getModel("login");
		const payload = {
			email: login.getProperty("/email"),
			password: login.getProperty("/password"),
			keepSignedIn: login.getProperty("/keepSignedIn"),
		};
		try {
			const response = await LaravelUi5.call<Record<string, unknown>, LoginResponse>(
				"io.pragmatiqu.auth.actions.login",
				{},
				payload
			);
			URLHelper.redirect(response.redirect, false);
		}
		catch (error) {
			const err = error as ActionError;
			MessageBox.error(err.cause.message, {title: err.statusText});
		}
	}
}
